import{c as a,Q as i,j as e,m as t}from"./chunks/framework.D9IbVcwA.js";const c=JSON.parse('{"title":"Fork CoW Huge Page","description":"","frontmatter":{"title":"Fork CoW Huge Page"},"headers":[],"relativePath":"notes/035/fork_cow_huge_page_filter.md","filePath":"notes/035/fork_cow_huge_page_filter.md","lastUpdated":1779686691000}'),n={name:"notes/035/fork_cow_huge_page_filter.md"};function p(h,s,l,r,d,k){return i(),e("div",null,[...s[0]||(s[0]=[t('<h1 id="_035-fork-cow-与-huge-page-过滤-方案-a-实施前安全审查" tabindex="-1">035 fork() CoW 与 Huge Page 过滤：方案 A 实施前安全审查 <a class="header-anchor" href="#_035-fork-cow-与-huge-page-过滤-方案-a-实施前安全审查" aria-label="Permalink to &quot;035 fork() CoW 与 Huge Page 过滤：方案 A 实施前安全审查&quot;">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>Cinux 的 PML4[0] 混合了内核恒等映射（无 FLAG_USER）和用户私有映射（有 FLAG_USER）。 fork() 当前复制整个 PML4[0..255]，包括不应该复制的内核映射（1GB MMIO 大页、2MB RAM 大页）。</p><p><strong>方案 A</strong>：在 <code>copy_page_table_level</code> 中按 <code>FLAG_USER</code> 过滤，跳过内核映射条目。 子进程通过共享的 PML4[256..511]（高半区）访问硬件。</p><p>实施前提：<strong>所有内核代码必须通过高半区地址访问硬件，不依赖 PML4[0] 恒等映射。</strong></p><h2 id="逐项审查结果" tabindex="-1">逐项审查结果 <a class="header-anchor" href="#逐项审查结果" aria-label="Permalink to &quot;逐项审查结果&quot;">​</a></h2><h3 id="_1-phys-to-virt-—-安全" tabindex="-1">1. <code>phys_to_virt()</code> — 安全 <a class="header-anchor" href="#_1-phys-to-virt-—-安全" aria-label="Permalink to &quot;1. `phys_to_virt()` — 安全&quot;">​</a></h3><p>三处实现（vmm.cpp、address_space.cpp、process.cpp）一致：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> reinterpret_cast&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PageEntry</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(phys </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">FFFFFFFF80000000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>正确使用高半区偏移。</p><h3 id="_2-cow-页拷贝-—-安全" tabindex="-1">2. CoW 页拷贝 — 安全 <a class="header-anchor" href="#_2-cow-页拷贝-—-安全" aria-label="Permalink to &quot;2. CoW 页拷贝 — 安全&quot;">​</a></h3><p>process.cpp 的 <code>handle_cow_fault()</code>：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> src </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> reinterpret_cast&lt;uint8_t*&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(old_phys </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KERNEL_VMA);</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dst </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> reinterpret_cast&lt;uint8_t*&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(new_phys </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KERNEL_VMA);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>源页和目标页都通过 <code>phys + KERNEL_VMA</code> 访问，不依赖恒等映射。</p><h3 id="_3-ahci-驱动-—-安全" tabindex="-1">3. AHCI 驱动 — 安全 <a class="header-anchor" href="#_3-ahci-驱动-—-安全" aria-label="Permalink to &quot;3. AHCI 驱动 — 安全&quot;">​</a></h3><p><code>AHCI::map_bar5()</code> 使用 <code>KMEM_MMIO_BASE</code>（高半区）映射 BAR5： 通过 <code>g_vmm.map(virt, phys, ...)</code> 创建独立映射，DMA 结构体也用 <code>phys + 0xFFFFFFFF80000000</code> 访问。</p><h3 id="_4-apic-—-n-a" tabindex="-1">4. APIC — N/A <a class="header-anchor" href="#_4-apic-—-n-a" aria-label="Permalink to &quot;4. APIC — N/A&quot;">​</a></h3><p>代码库中不存在 APIC 实现。</p><h3 id="_5-framebuffer-—-阻塞项-已修复" tabindex="-1">5. Framebuffer — 阻塞项（已修复） <a class="header-anchor" href="#_5-framebuffer-—-阻塞项-已修复" aria-label="Permalink to &quot;5. Framebuffer — 阻塞项（已修复）&quot;">​</a></h3><p>原实现：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// framebuffer.cpp（修复前）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addr_ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> reinterpret_cast&lt;volatile</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> uint32_t*&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fb_phys);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 0xFD000000 恒等映射！</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这是唯一的阻塞项。Framebuffer 驱动直接将物理地址 <code>0xFD000000</code> 当作虚拟地址使用， 完全依赖 PML4[0] 的恒等映射。</p><h2 id="framebuffer-修复过程与踩坑" tabindex="-1">Framebuffer 修复过程与踩坑 <a class="header-anchor" href="#framebuffer-修复过程与踩坑" aria-label="Permalink to &quot;Framebuffer 修复过程与踩坑&quot;">​</a></h2><h3 id="第一版-直接加-kernel-vma-偏移-—-黑屏" tabindex="-1">第一版：直接加 KERNEL_VMA 偏移 — 黑屏 <a class="header-anchor" href="#第一版-直接加-kernel-vma-偏移-—-黑屏" aria-label="Permalink to &quot;第一版：直接加 KERNEL_VMA 偏移 — 黑屏&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addr_ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> reinterpret_cast&lt;volatile</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> uint32_t*&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fb_phys </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KERNEL_VMA);</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 0xFD000000 + 0xFFFFFFFF80000000 = 0xFFFFFFFFFD000000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>结果</strong>：黑屏。<code>0xFFFFFFFFFD000000</code> 在高半区页表中没有对应的页表映射。 高半区直映射只覆盖了内核代码段所在的物理 RAM 范围，不覆盖 MMIO 地址（0xFD000000）。</p><h3 id="第二版-用-vmm-映射-4kb-页到-kmem-fb-base-—-极慢" tabindex="-1">第二版：用 VMM 映射 4KB 页到 KMEM_FB_BASE — 极慢 <a class="header-anchor" href="#第二版-用-vmm-映射-4kb-页到-kmem-fb-base-—-极慢" aria-label="Permalink to &quot;第二版：用 VMM 映射 4KB 页到 KMEM_FB_BASE — 极慢&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">uint64_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> num_pages; i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">++</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    g_vmm.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">map</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(KMEM_FB_BASE </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PAGE_SIZE, fb_phys </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PAGE_SIZE, mmio_flags);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>结果</strong>：画面恢复但性能暴跌。8MB framebuffer 需要 ~2048 个 4KB 页表条目， 远超 L1/L2 TLB 容量（约 64+512 条），导致 TLB 抖动，每次像素写入都触发页表遍历。</p><h3 id="第三版-vmm-新增-map-2mb-—-仍有性能问题" tabindex="-1">第三版：VMM 新增 <code>map_2mb()</code> — 仍有性能问题 <a class="header-anchor" href="#第三版-vmm-新增-map-2mb-—-仍有性能问题" aria-label="Permalink to &quot;第三版：VMM 新增 `map_2mb()` — 仍有性能问题&quot;">​</a></h3><p>给 VMM 加了 <code>map_2mb()</code> 方法，用 2MB 大页映射。TLB 条目从 ~2048 降到 ~4 个。</p><p><strong>结果</strong>：略有缓解但仍抖动。原因：映射时加了 <code>FLAG_PCD</code>（Cache Disable）。 原 <code>map_mmio()</code> 使用 <code>FLAG_PRESENT | FLAG_WRITABLE</code>（无 PCD），framebuffer 是缓存写回的。 加了 PCD 后每次像素写入都直通内存，在 QEMU 中极慢。</p><h3 id="最终版-去掉-flag-pcd-—-修复" tabindex="-1">最终版：去掉 FLAG_PCD — 修复 <a class="header-anchor" href="#最终版-去掉-flag-pcd-—-修复" aria-label="Permalink to &quot;最终版：去掉 FLAG_PCD — 修复&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">constexpr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> uint64_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mmio_flags </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> arch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::FLAG_PRESENT </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> arch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::FLAG_WRITABLE;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>去掉 PCD 后性能恢复正常。QEMU 的 framebuffer 就是 host 内存，缓存写回完全可行。</p><h2 id="最终改动汇总" tabindex="-1">最终改动汇总 <a class="header-anchor" href="#最终改动汇总" aria-label="Permalink to &quot;最终改动汇总&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>改动</th></tr></thead><tbody><tr><td><code>memory_layout.hpp</code></td><td>新增 <code>KERNEL_VMA</code> 共享常量 + <code>KMEM_FB_SIZE/BASE</code> 区域</td></tr><tr><td><code>vmm.hpp/cpp</code></td><td>新增 <code>map_2mb()</code> 方法</td></tr><tr><td><code>framebuffer.cpp</code></td><td>用 <code>g_vmm.map_2mb()</code> 映射到 <code>KMEM_FB_BASE</code>，不再依赖 PML4[0]</td></tr></tbody></table><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p>方案 A 的安全审查通过。唯一的阻塞项（Framebuffer 恒等映射）已修复。 所有内核硬件访问路径（CoW、AHCI、Framebuffer）现在都走高半区映射。</p><p><strong>可以安全实施 <code>FLAG_USER</code> 过滤。</strong></p>',40)])])}const E=a(n,[["render",p]]);export{c as __pageData,E as default};
